{"command": "python3 -c "
import os, json, urllib.request
tok = os.environ.get('GITHUB_TOKEN','').strip()
print('env GITHUB_TOKEN present:', bool(tok), 'len:', len(tok), 'mask:', (tok[:4]+'****'+tok[-4:]) if len(tok)>8 else 'n/a')
if tok:
    req = urllib.request.Request('https://api.github.com/user', headers={'Authorization': f'Bearer {tok}', 'Accept': 'application/vnd.github+json', 'User-Agent': 'ivx-check'})
    try:
        r = json.load(urllib.request.urlopen(req))
        print('AUTH OK as:', r.get('login'))
        open('/tmp/gh_token','w').write(tok)
    except Exception as e:
        print('env token auth FAILED:', e)
""}

